96	fn writeStdout(s: []const u8) void {
97	    _ = std.c.write(1, s.ptr, s.len);
98	}
99	
100	const Flags = struct {
101	    force_256: bool = false,
102	    control_mode: bool = false,
103	    shell_command: ?[:0]const u8 = null,
104	    no_daemon: bool = false,
105	    config_file: ?[:0]const u8 = null,
106	    socket_name: ?[:0]const u8 = null,
107	    socket_path: ?[:0]const u8 = null,
108	    utf8_flag: bool = false,
109	    verbose: u8 = 0,
110	    print_version: bool = false,
111	    remaining: std.ArrayListAligned([:0]const u8, null),
112	
113	    fn deinit(self: *Flags, alloc: std.mem.Allocator) void {
114	        self.remaining.deinit(alloc);
115	    }
116	};
117	
118	fn getenv(name: [:0]const u8) ?[]const u8 {
119	    const value = std.c.getenv(name) orelse return null;
120	    return std.mem.sliceTo(value, 0);
121	}
122	
123	fn parseArgs(alloc: std.mem.Allocator, init_args: std.process.Args) Flags {
124	    var flags = Flags{ .remaining = .empty };
125	    var args = std.process.Args.Iterator.init(init_args);
126	    _ = args.next();
127	
128	    while (args.next()) |arg| {
129	        if (arg.len < 2 or arg[0] != '-') {
130	            flags.remaining.append(alloc, arg) catch {};
131	            while (args.next()) |rest| {
132	                flags.remaining.append(alloc, rest) catch {};
133	            }
134	            break;
135	        }
136	        for (arg[1..]) |c| {
137	            switch (c) {
138	                '2' => flags.force_256 = true,
139	                'C' => flags.control_mode = true,
140	                'D' => flags.no_daemon = true,
141	                'u' => flags.utf8_flag = true,
142	                'v' => flags.verbose +|= 1,
143	                'V' => flags.print_version = true,
144	                'c' => {
145	                    flags.shell_command = args.next();
146	                    break;
147	                },
148	                'f' => {
149	                    flags.config_file = args.next();
150	                    break;
151	                },
152	                'L' => {
153	                    flags.socket_name = args.next();
154	                    break;
155	                },
156	                'S' => {
157	                    flags.socket_path = args.next();
158	                    break;
159	                },
160	                else => {},
161	            }
162	        }
163	    }
164	    return flags;
165	}
166	
167	fn resolveSocketPath(alloc: std.mem.Allocator, flags: *const Flags) ![]u8 {
168	    if (flags.socket_path) |path| {
169	        return try alloc.dupe(u8, path);
170	    }
171	    if (getenv("AGENTMUX_SOCKET_PATH")) |path| {
172	        return try alloc.dupe(u8, path);
173	    }
174	
175	    const socket_dir = try platform.core.defaultSocketDir(alloc);
176	    defer alloc.free(socket_dir);
177	    const socket_name = if (flags.socket_name) |sn|
178	        sn
179	    else if (getenv("AGENTMUX_SOCKET_NAME")) |sn|
180	        sn
181	    else
182	        default_socket_name;
183	
184	    return try std.fmt.allocPrint(alloc, "{s}/agentmux-{d}/{s}", .{
185	        socket_dir,
186	        std.c.getuid(),
187	        socket_name,
188	    });
189	}
190	
191	fn determineTerminalName() []const u8 {
192	    return getenv("TERM") orelse "xterm-256color";
193	}
194	
195	fn runServer(alloc: std.mem.Allocator, socket_path: []const u8, daemonize_server: bool) !void {
196	    if (daemonize_server) {
197	        try signals.daemonize();
198	    }
199	    signals.SignalHandler.install();
200	    var server = try server_mod.Server.init(alloc, socket_path);
201	    defer server.deinit();
202	    try server.listen();
203	    try server.run();
204	}
205	
206	fn waitForServer(alloc: std.mem.Allocator, socket_path: []const u8) !void {
207	    var attempt: usize = 0;
208	    while (attempt < 100) : (attempt += 1) {
209	        var probe = client_mod.Client.init(alloc, socket_path);
210	        if (probe.connect()) {
211	            probe.disconnect();
212	            return;
213	        } else |_| {
214	            var delay = std.c.timespec{
215	                .sec = 0,
216	                .nsec = 50 * std.time.ns_per_ms,
217	            };
218	            _ = std.c.nanosleep(&delay, null);
219	        }
220	    }
221	    return error.ServerStartTimeout;
222	}
223	
224	fn autostartServer(alloc: std.mem.Allocator, socket_path: []const u8) !void {
225	    const pid = std.c.fork();
226	    if (pid < 0) return error.ForkFailed;
227	    if (pid == 0) {
228	        detachStdio();
229	        runServer(std.heap.c_allocator, socket_path, false) catch {};
230	        std.c.exit(0);
231	    }
232	    try waitForServer(alloc, socket_path);
233	}
234	
235	fn detachStdio() void {
236	    _ = std.c.setsid();
237	    _ = std.c.close(0);
238	    _ = std.c.close(1);
239	    _ = std.c.close(2);
240	
241	    const devnull: [*:0]const u8 = "/dev/null";
242	    const fd = std.c.open(devnull, .{ .ACCMODE = .RDWR }, @as(std.c.mode_t, 0));
243	    if (fd < 0) return;
244	    _ = std.c.dup2(fd, 0);
245	    _ = std.c.dup2(fd, 1);
246	    _ = std.c.dup2(fd, 2);
247	    if (fd > 2) _ = std.c.close(fd);
248	}
249	
250	fn runCommandMode(alloc: std.mem.Allocator, flags: *const Flags, socket_path: []const u8) !void {
251	    var client = client_mod.Client.init(alloc, socket_path);
252	    client.connect() catch |err| switch (err) {
253	        error.ConnectFailed => {
254	            try autostartServer(alloc, socket_path);
255	            try client.connect();
256	        },
257	        else => return err,
258	    };
259	    defer client.disconnect();
260	
261	    try client.identify(determineTerminalName(), 80, 24);
262	    const result = try client.requestCommand(flags.remaining.items);
263	    if (result.exit_code != 0) {
264	        std.c.exit(result.exit_code);
265	    }
266	}
267	
268	pub fn main(init: std.process.Init.Minimal) !void {
269	    var agentmux_alloc = core.allocator_mod.AgentmuxAllocator.init();
270	    defer agentmux_alloc.deinit();
271	    const alloc = agentmux_alloc.allocator();
272	
273	    var flags = parseArgs(alloc, init.args);
274	    defer flags.deinit(alloc);
275	
276	    if (flags.print_version) {
277	        writeStdout(version_string ++ "\n");
278	        return;
279	    }
280	
281	    const log_level: log.Level = switch (flags.verbose) {
282	        0 => .info,
283	        else => .debug,
284	    };
285	    log.init(log_level, null, flags.verbose > 0);
286	    defer log.deinit();
287	
288	    const socket_path = try resolveSocketPath(alloc, &flags);
289	    defer alloc.free(socket_path);
290	
291	    if (flags.remaining.items.len == 0) {
292	        try runServer(alloc, socket_path, !flags.no_daemon);
293	        return;
294	    }
295	
296	    try runCommandMode(alloc, &flags, socket_path);
297	}
